// Parse request for different Claude use cases
const input = $input.first().json.body || $input.first().json;

const testCase = input.test_case || "simple";
const data = input.data || "";

let command = "";
let description = "";

switch(testCase) {
  case "simple":
    // Simple question
    command = `claude -p "What is the capital of France?"`;
    description = "Simple question test";
    break;

  case "math":
    // Math problem
    command = `claude -p "Calculate: (15 * 23) + (47 / 3) - 12"`;
    description = "Math calculation test";
    break;

  case "json":
    // JSON output
    command = `claude -p "List 3 programming languages with their creation years" --output-format json`;
    description = "JSON output test";
    break;

  case "code_review":
    // Code review with piped input
    const code = data || `
function fibonacci(n) {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}
`;
    command = `echo '${code.replace(/'/g, "'\\''")}' | claude -p "Review this code for performance and suggest improvements"`;
    description = "Code review test";
    break;

  case "tech_lead":
    // Tech LEAD decision making
    const context = {
      role: "Tech LEAD",
      task: "select_issue",
      issues: [
        {number: 1, title: "Add user authentication", priority: "high"},
        {number: 2, title: "Fix typo in README", priority: "low"},
        {number: 3, title: "Implement API endpoints", priority: "medium"}
      ]
    };
    command = `echo '${JSON.stringify(context)}' | claude -p "You are Tech LEAD. Analyze these issues and select which one to work on first. Output your decision as JSON with fields: selected_issue_number, reasoning, estimated_hours" --output-format json`;
    description = "Tech LEAD decision test";
    break;

  case "multi_turn":
    // Multi-turn conversation (limited support in CLI)
    command = `claude -p "First, explain what recursion is. Then give a Python example." --max-turns 2`;
    description = "Multi-turn test";
    break;

  case "pipe_chain":
    // Chaining commands
    command = `echo "Write a haiku about programming" | claude -p "Process this request" | wc -l`;
    description = "Pipe chain test";
    break;

  default:
    // Custom prompt from input
    command = `claude -p "${input.prompt || 'Hello, Claude'}"`;
    description = "Custom prompt test";
}

return {
  test_case: testCase,
  command: command,
  description: description,
  timestamp: new Date().toISOString()
};

// Process and format the Claude response
const item = $input.first().json;

let result = {
  success: false,
  test_case: item.test_case,
  description: item.description,
  command: item.command,
  timestamp: item.timestamp,
  response: null,
  parsed_json: null,
  error: null,
  execution_time: null
};

// Calculate execution time (rough estimate)
const start = new Date(item.timestamp);
const end = new Date();
result.execution_time = `${(end - start) / 1000}s`;

if (item.exitCode === 0) {
  result.success = true;
  result.response = item.stdout ? item.stdout.trim() : "";

  // Try to parse as JSON if it looks like JSON
  if (result.response && (result.response.startsWith('{') || result.response.startsWith('['))) {
    try {
      result.parsed_json = JSON.parse(result.response);
    } catch (e) {
      // Not JSON or invalid JSON, keep as string
    }
  }
} else {
  result.error = item.stderr || "Command failed with no error message";
}

// Add metadata for Tech LEAD integration
if (item.test_case === "tech_lead" && result.parsed_json) {
  result.tech_lead_decision = {
    ready_for_execution: true,
    selected_issue: result.parsed_json.selected_issue_number,
    reasoning: result.parsed_json.reasoning,
    estimated_hours: result.parsed_json.estimated_hours
  };
}

return result;
